#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>

typedef struct { long long n; long long val; } MemoEntry;
static MemoEntry memo[200000];
static int memoSize = 0;

long long getMemo(long long n) {
    for (int i = 0; i < memoSize; ++i) if (memo[i].n == n) return memo[i].val;
    return -1;
}

void setMemo(long long n, long long v) {
    memo[memoSize].n = n;
    memo[memoSize].val = v;
    ++memoSize;
}

long long sumPhi(long long n) {
    if (n <= 0) return 0;
    long long cached = getMemo(n);
    if (cached != -1) return cached;
    long long res = n * (n + 1) / 2; // initial term
    long long i = 2;
    while (i <= n) {
        long long q = n / i;
        long long next = n / q;
        res -= (next - i + 1) * sumPhi(q);
        i = next + 1;
    }
    setMemo(n, res);
    return res;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, D; scanf("%lld %lld", &N, &D);
        if (D > N) {
            printf("0\n");
            continue;
        }
        long long M = N / D;
        long long ans = sumPhi(M);
        printf("%lld\n", ans);
    }
    return 0;
}

