#include <bits/stdc++.h>
using namespace std;
using int64 = long long;

unordered_map<int64,int64> memo;

int64 sumPhi(int64 n){
    if(n<=0) return 0;
    auto it = memo.find(n);
    if(it!=memo.end()) return it->second;
    int64 res = n*(n+1)/2; // n*(n+1)/2 = Σ_{i=1}^n i
    for(int64 i=2;i<=n;){
        int64 q = n/i;
        int64 nxt = n/q;
        res -= (nxt - i + 1) * sumPhi(q);
        i = nxt + 1;
    }
    memo[n]=res;
    return res;
}

int main(){
    ios::sync_with_stdio(false);
